INSERT INTO public.industry_issue (full_name, first_name, last_name, headline, linkedin_url, public_identifier, raw_data) VALUES
('Charlie Springthorpe', 'Charlie', 'Springthorpe', 'General Manager @ Jai Tiki Retreat, Koh Lanta', 'https://www.linkedin.com/in/charlie-springthorpe-1b3b625b', 'charlie-springthorpe-1b3b625b', $${"about": "I graduated from Lancaster University with a First class degree in joint honours Advertising & Marketing in 2016. After completing my degree, I took part in, and graduated from, the coveted IDM Summer School, before relocating to Australia where I continued to gain experience in the marketing sector.\n\nI have strong experience in FMCG Brand Management with a background across haircare, lifestyle, soft drinks and health & fitness industries.\n\nI am experienced working with high-profile corporations, such as L’Oréal, Wimbledon and Britvic Soft\nDrinks, managing budgets up to £10M and delivering strong brand performance through P&L\nmanagement, NPD/ EPD and brand communication campaigns.\n\nCreative, enthusiastic and passionate best describes my attitude. I take a ‘can do’ approach to all that is thrown at me, and complete tasks with attention to detail. My insights profile describes me as an ingenious and original problem solver who sees possibilities beyond what is currently known or accepted.", "addressCountryOnly": "Thailand", "addressWithCountry": "Ko Lanta, Krabi, Thailand", "addressWithoutCountry": "Ko Lanta, Krabi", "backgroundPic": "https://media.licdn.com/dms/image/v2/D4E16AQHxq-g4iAC8NQ/profile-displaybackgroundimage-shrink_350_1400/B4EZqlvoTEHgAY-/0/1763717319163?e=1778112000&v=beta&t=-xeq6vDbcvUFhuEI7GMuGf4jSKsbl987gRTsvYcJAQ0", "companyName": "Jai Tiki Retreat", "connections": "913", "currentJobDuration": "11 mos", "currentJobDurationInYrs": "0.92", "educations/0/companyId": "12603", "educations/0/companyLink1": "https://www.linkedin.com/school/lancaster-university/", "educations/0/companyUrn": "urn:li:fsd_company:12603", "educations/0/grade": "First", "educations/0/logo": "https://media.licdn.com/dms/image/v2/C4E0BAQGKio0Euee3Lw/company-logo_200_200/company-logo_200_200/0/1631301666319?e=1778112000&v=beta&t=hWPg1tm5wiUWzP5vWFPqUiiEp0-FAXX94Prd_qlKLCA", "educations/0/period/endedOn/month": "0", "educations/0/period/endedOn/year": "2016", "educations/0/period/startedOn/month": "0", "educations/0/period/startedOn/year": "2012", "educations/0/subtitle": "Bachelor of Arts (B.A.), Advertising and Marketing", "educations/0/title": "Lancaster University", "educations/1/companyId": "22478", "educations/1/companyLink1": "https://www.linkedin.com/school/the-institute-of-direct-and-digital-marketing/", "educations/1/companyUrn": "urn:li:fsd_company:22478", "educations/1/description": "Selected as one of thirty students (out of 240) from across the UK to attend a one week Marketing course at the IDM, Teddington. \n\nOne aspect of the course involved completing  a live brief, set by The Economist, and presenting it to a range of industry professionals under a tight deadline. I also visited top global advertising agencies and participated in work shops delivered by marketing experts.", "educations/1/grade": "Graduated", "educations/1/logo": "https://media.licdn.com/dms/image/v2/C510BAQFUyc60hSPVOg/company-logo_200_200/company-logo_200_200/0/1631390973101?e=1778112000&v=beta&t=KokpWbRKOrrAUnOXp2zwN73_-IxBu2nIXYpX3D10lAY", "educations/1/period/endedOn/month": "0", "educations/1/period/endedOn/year": "2016", "educations/1/period/startedOn/month": "0", "educations/1/period/startedOn/year": "2016", "educations/1/subtitle": "IDM Summer School, Direct and Digital Marketing", "educations/1/title": "The Institute of Direct and Digital Marketing", "educations/2/grade": "A - A*", "educations/2/period/endedOn/month": "0", "educations/2/period/endedOn/year": "2012", "educations/2/period/startedOn/month": "0", "educations/2/period/startedOn/year": "2010", "educations/2/subtitle": "A Levels, Art & Design, Media, French, Maths", "educations/2/title": "Countesthorpe Community College", "experiences/0/companyName": "Jai Tiki Retreat", "experiences/0/employmentType": "Full-time", "experiences/0/jobLocation": "Ko Lanta, Krabi, Thailand", "experiences/0/jobStartedOn": "6-2025", "experiences/0/jobStillWorking": "true", "experiences/0/title": "General Manager", "experiences/1/companyId": "1662", "experiences/1/companyIndustry": "Personal Care Product Manufacturing", "experiences/1/companyLink1": "https://www.linkedin.com/company/lor%C3%A9al/", "experiences/1/companyName": "L'Oréal", "experiences/1/companySize": "10001-0", "experiences/1/companyUrn": "urn:li:fsd_company:1662", "experiences/1/companyWebsite": "http://www.loreal.com", "experiences/1/employmentType": "Full-time", "experiences/1/jobLocation": "Kuala Lumpur, Federal Territory of Kuala Lumpur, Malaysia", "experiences/1/jobLocationCountry": "FR", "experiences/1/jobStartedOn": "2-2023", "experiences/1/jobStillWorking": "true", "experiences/1/logo": "https://media.licdn.com/dms/image/v2/D4E0BAQFEB_g-FWxSrQ/company-logo_400_400/company-logo_400_400/0/1688397792617/loral_logo?e=1778112000&v=beta&t=AsaQT4Asgdj5ym2LoautNJokQpD6hyZXGdgrsI5sBpg", "experiences/1/title": "Community & Digital Manager", "experiences/2/companyId": "1662", "experiences/2/companyIndustry": "Personal Care Product Manufacturing", "experiences/2/companyLink1": "https://www.linkedin.com/company/lor%C3%A9al/", "experiences/2/companyName": "L'Oréal", "experiences/2/companySize": "10001-0", "experiences/2/companyUrn": "urn:li:fsd_company:1662", "experiences/2/companyWebsite": "http://www.loreal.com", "experiences/2/employmentType": "Full-time", "experiences/2/jobEndedOn": "2-2023", "experiences/2/jobLocation": "London, England Metropolitan Area", "experiences/2/jobLocationCountry": "FR", "experiences/2/jobStartedOn": "9-2020", "experiences/2/jobStillWorking": "false", "experiences/2/logo": "https://media.licdn.com/dms/image/v2/D4E0BAQFEB_g-FWxSrQ/company-logo_400_400/company-logo_400_400/0/1688397792617/loral_logo?e=1778112000&v=beta&t=AsaQT4Asgdj5ym2LoautNJokQpD6hyZXGdgrsI5sBpg", "experiences/2/title": "Brand Manager", "experiences/3/companyId": "2624908", "experiences/3/companyIndustry": "Wellness and Fitness Services", "experiences/3/companyLink1": "https://www.linkedin.com/company/gympass/", "experiences/3/companyName": "Gympass", "experiences/3/companySize": "1001-5000", "experiences/3/companyUrn": "urn:li:fsd_company:2624908", "experiences/3/companyWebsite": "https://wellhub.com", "experiences/3/employmentType": "Full-time", "experiences/3/jobDescription": "Gympass is a health and fitness aggregator platform. With 3 direct reports, my role was to devise\nstrategies and campaigns to drive brand awareness, predominately though experiential and digital\nmarketing. The overall strategic approach remained constant but the campaign and launch strategies\nwere bespoke per client.\n\n• Pitched and implemented a bold new strategy to the CEO including a team restructure.\n\n• Leveraged neuroscience principles to increase impact of the current approach; moving results from\n10 to 128 sign ups per event.\n\n• Building client campaigns based on consumer driven insight has allowed me to organise campaigns\n3-6 months in advance, vs clients only being comfortable proceeding an event at a time.", "experiences/3/jobEndedOn": "8-2020", "experiences/3/jobLocation": "London, United Kingdom", "experiences/3/jobLocationCountry": "US", "experiences/3/jobStartedOn": "11-2019", "experiences/3/jobStillWorking": "false", "experiences/3/logo": "https://media.licdn.com/dms/image/v2/D4D0BAQHUUt2GZC14cA/company-logo_400_400/company-logo_400_400/0/1712841082877/gympass_logo?e=1778112000&v=beta&t=Q8tn-yzXQ7qthT8ExVUTW_WJ8Vc63FcsluLN3zDIz9w", "experiences/3/title": "Activation Manager", "experiences/4/companyId": "10540", "experiences/4/companyIndustry": "Consumer Services", "experiences/4/companyLink1": "https://www.linkedin.com/company/britvic-soft-drinks/", "experiences/4/companyName": "BRITVIC PLC", "experiences/4/companySize": "1001-5000", "experiences/4/companyUrn": "urn:li:fsd_company:10540", "experiences/4/companyWebsite": "http://www.britvic.com", "experiences/4/jobDescription": "Aqua Libra is Britvic’s innovation brand. My main responsibilities were; to manage NPD\nfrom conception to launch; to oversee brand operations including performance reviews, A&P \nand 4P management; and finally to lead the brand planning and AOP.\n\n• Developed and launched a flavour extension which delivered +57% in ROS.\n\n• Developed and launched a pack format which unlocked 2 major new accounts.\n\n• Successfully planned and executed a multifaceted campaign which included a bespoke Media and\nInfluencer event, social media, PR, experiential and a 3-month partnership with Stylist Magazine.\nPresented plans to CMO.\n\n• The campaign increased awareness from 15% to 17% (highest in the category) and increased\nMental Market Share from 0.2 to 4.2.", "experiences/4/jobEndedOn": "11-2019", "experiences/4/jobLocation": "London, United Kingdom", "experiences/4/jobLocationCountry": "GB", "experiences/4/jobStartedOn": "11-2018", "experiences/4/jobStillWorking": "false", "experiences/4/logo": "https://media.licdn.com/dms/image/v2/D4E0BAQHWCR8blPmZHw/company-logo_400_400/B4EZg2JG.iGoAc-/0/1753255014666/britvic_soft_drinks_logo?e=1778112000&v=beta&t=bojRruI4fgCXGsr4NuslO1s_Hni8nZMLi6qYtM9VyOk", "experiences/4/title": "Brand Manager - Aqua Libra", "experiences/5/companyId": "10540", "experiences/5/companyIndustry": "Consumer Services", "experiences/5/companyLink1": "https://www.linkedin.com/company/britvic-soft-drinks/", "experiences/5/companyName": "BRITVIC PLC", "experiences/5/companySize": "1001-5000", "experiences/5/companyUrn": "urn:li:fsd_company:10540", "experiences/5/companyWebsite": "http://www.britvic.com", "experiences/5/jobDescription": "Robinsons is the UK’s favourite squash brand and is well known for its long-standing partnership with Wimbledon. My main responsibilities to date include budget management for the Robinsons team, event management for the Wimbledon partnership and brand management for Robinsons Squash’d.\n\nWimbledon comprises of multiple activations across 7 agencies which I have lead all the way from briefing, and implementation, to the review and evaluation. I ran the biggest social media competition that Robinsons has ever had, resulting in c.3.6K entries (+1000% vs LY) and a reach of over 1.4m. I also ran multiple media partner competitions including a 30 second advert with Heart Radio, collectively resulting in c.34m opportunities to see. \n\nTo support Britvic’s sustainability agenda and to increase traffic to the Robinsons Café at Wimbledon, I developed an activation which allowed people to get their name printed on a limited-edition reusable Robinsons bottle. This plan received so much traction both internally and with the All England Lawn Tennis Club, that we received incremental funds and support allowing us to produce a short piece of video content for the press. \n\nNow Wimbledon 2018 is complete, I am focusing on the development of the 2019 strategy for Robinsons Squash’d, adhering to the Ehrenberg-Bass principles.\n\nI also had ownership of the Squash'd sub brand. I step changed the performance of Squash’d from double digit decline to 2% growth through the promotional mix, NPD to a more sustainable and cheaper format, and brand redesign from a ‘subtly endorsed’, to a full ‘parent led’ strategy. I led this project for UK, IE and BENELUX regions as the Global Marketing Controller role was vacant", "experiences/5/jobEndedOn": "11-2018", "experiences/5/jobLocation": "London, United Kingdom", "experiences/5/jobLocationCountry": "GB", "experiences/5/jobStartedOn": "9-2017", "experiences/5/jobStillWorking": "false", "experiences/5/logo": "https://media.licdn.com/dms/image/v2/D4E0BAQHWCR8blPmZHw/company-logo_400_400/B4EZg2JG.iGoAc-/0/1753255014666/britvic_soft_drinks_logo?e=1778112000&v=beta&t=bojRruI4fgCXGsr4NuslO1s_Hni8nZMLi6qYtM9VyOk", "experiences/5/title": "Assistant Brand Manager - Robinsons", "experiences/6/companyName": "Independent", "experiences/6/jobDescription": "After my fixed term contract role in Australia, I spent 4 months on a solo trip around 9 countries in Asia and Australasia. I spent a great deal of time at volunteering projects. These included; \n\n- Teaching English to children in Bali in a remote village called Seraya;\n- Feeding, bathing and supporting elephants in South-East Thailand; and\n- Building a community centre for an under privileged community in North Thailand. \n\nWhen I wasn’t volunteering, I spent my time exploring new cultures, meeting new people and learning the local languages. As well as being an amazing, memorable experience, I believe this trip was highly beneficial to me as it developed my cultural awareness greatly, and helped me heighten my competencies in communication and organisation. My adaptability and social skills were also strengthened as when things did not go to plan, I was able to swiftly reconfigure them whilst still maintaining my confident and bubbly persona!", "experiences/6/jobEndedOn": "10-2017", "experiences/6/jobLocation": "Asia", "experiences/6/jobStartedOn": "5-2017", "experiences/6/jobStillWorking": "false", "experiences/6/title": "Travelling Around Asia & Australasia", "experiences/7/companyName": "Speciality Fashion Group", "experiences/7/jobDescription": "SFG is the largest specialty retailer of women’s fashion in Australasia comprising of 7 commercial brands. My role at SFG started out as a Brand Assistant, reporting directly to the General Manager for two brands; the corporate charity (1Woman Foundation), and the newest commercial brand (One Woman). My responsibilities included:\n\n•\tAnalysing and interpreting data, providing key action points from the results,\n•\tRaising purchase orders and allocating products\n•\tAssisting the development and implementation of the brand strategy,\n•\tRedesigning and copywriting for the new One Woman website, \n•\tCreating point of sale marketing stimuli and general brand communications,\n•\tDesigning briefs for creative agencies, \n\nOnly a couple of months in, my Line Manager (the GM) left with no hand over period, leaving me to take more responsibility and tasks. I quickly became the acting Brand Manager and primary contact for both brands. I was largely responsible for maintaining brand guidelines across all brand communications as well as the continued implementation of the brand strategy. Another large addition to my workload was the management of the 1Woman Foundation. \n\n•\tThe Foundation’s website and marketing materials had long been neglected, so after successfully presenting my ideas to the CEO, I created and launched a new brand website with fully optimised search engine performance, as well as a new range of marketing materials in keeping with the new brand image. \n\n•\tThe Foundation partly generates income by selling water bottles in circa 1000 SFG stores. Previously I looked after the allocations, packaging and sales of these bottles; however I saw room for improvement and I initiated a plan between logistics, the vendor and myself, which saved the Foundation $85.8K every 6 months. \n\n•\tLast financial year the Foundation had 16 volunteers work on a one day project. I implemented and managed frequent successful volunteering sessions with around 20 volunteers per month.", "experiences/7/jobEndedOn": "5-2017", "experiences/7/jobLocation": "Sydney, Australia", "experiences/7/jobStartedOn": "11-2016", "experiences/7/jobStillWorking": "false", "experiences/7/title": "Brand Assistant", "experiences/8/companyName": "Think Management", "experiences/8/jobDescription": "To support my degree studies, particularly the digital marketing module, I worked at Think Management who provides digital marketing services to the gaming and gambling sector.\n\nMy role was as a consultant on a small number of accounts, providing; \n• Social media services (e.g. blogs, Facebook, Twitter and LinkedIn) \n\n• Website re-structuring and enhancement, including copy, Search Engine Optimisation (SEO), and consumer behaviour analysis (e.g. Google Analytics).\n\n• Marketing research (e.g. prior to new product development and launch).\n                                           \n                                              -------------------------------------------------\n\n(I took a years leave from this role whilst I completed my internship at L'Oréal)", "experiences/8/jobEndedOn": "9-2016", "experiences/8/jobLocation": "InfoLab, Lancaster", "experiences/8/jobStartedOn": "12-2012", "experiences/8/jobStillWorking": "false", "experiences/8/title": "Marketing Consultant", "experiences/9/companyId": "1662", "experiences/9/companyIndustry": "Personal Care Product Manufacturing", "experiences/9/companyLink1": "https://www.linkedin.com/company/lor%C3%A9al/", "experiences/9/companyName": "L'Oréal", "experiences/9/companySize": "10001-0", "experiences/9/companyUrn": "urn:li:fsd_company:1662", "experiences/9/companyWebsite": "http://www.loreal.com", "experiences/9/jobDescription": "At the end of the 2nd year of my degree, L’Oreal offered me a 12 month Marketing Internship position – my degree course was supposed to be 3 consecutive years, but the university were supportive.\n\nMy key responsibilities were;\n• Publishing – I managed, edited and published the Redken monthly magazine which is distributed to around 3,000 salons in the UK. This involved co-ordination of people (senior managers through to sales reps) throughout the month to ensure tight deadlines were met, and the quality of the content was great.\n\n• Project Management – I worked closely with 20th Century Fox to secure a partnership deal which allowed Redken to use aspects of a film in marketing material.\n\n• Reporting – Each week I performed reporting for the Redken management team to show sales performance against relevant targets (e.g. units sold, revenue generated, number of salons targeted). My role was to highlight areas of potential under-performance.\n\n• Event Management – I was part of a team involved in many marketing events to promote / launch Redken / Pureology products, including catering, logistics, event dressing, photography etc. \n\n• Social Media – I managed the social media accounts for the Pureology brand, including social   media posts, campaigns and graphic development.", "experiences/9/jobEndedOn": "7-2015", "experiences/9/jobLocationCountry": "FR", "experiences/9/jobStartedOn": "6-2014", "experiences/9/jobStillWorking": "false", "experiences/9/logo": "https://media.licdn.com/dms/image/v2/D4E0BAQFEB_g-FWxSrQ/company-logo_400_400/company-logo_400_400/0/1688397792617/loral_logo?e=1778112000&v=beta&t=AsaQT4Asgdj5ym2LoautNJokQpD6hyZXGdgrsI5sBpg", "experiences/9/title": "Marketing Intern (Redken & Pureology Brands)", "experiences/10/companyId": "2835", "experiences/10/companyIndustry": "Personal Care Product Manufacturing", "experiences/10/companyLink1": "https://www.linkedin.com/company/marykayglobal/", "experiences/10/companyName": "Mary Kay Inc.", "experiences/10/companySize": "1001-5000", "experiences/10/companyUrn": "urn:li:fsd_company:2835", "experiences/10/companyWebsite": "http://www.marykay.com/corporatecareers", "experiences/10/jobDescription": "During my last 2 years at Countesthorpe College I wanted to gain some useful work experience, and became a PA to one of Mary Kay’s consultants (Barbara Von Ow-Hulme).\n\nMy duties included;\n• Maintaining the client database\n• Updating expenses\n• Checking orders\n• Updating Invoices\n• General filing tasks", "experiences/10/jobEndedOn": "9-2012", "experiences/10/jobLocationCountry": "US", "experiences/10/jobStartedOn": "1-2011", "experiences/10/jobStillWorking": "false", "experiences/10/logo": "https://media.licdn.com/dms/image/v2/D560BAQHqSiBWOfrMZg/company-logo_400_400/B56Zz8e3uFJMAc-/0/1773762477273/marykayglobal_logo?e=1778112000&v=beta&t=F8Fq9VRlX19pOOWI41b5eSiLPypOooBwhzd7FQRLEqQ", "experiences/10/tit